module top_module(
    input clk,
    input load,
    input up_down,
    output reg [2:0] out
);reg [2:0] obf_reg1, reg2, reg3;

always @(posedge clk) begin
    if (load) begin
        obf_reg1 <= 3'b0;
        reg2 <= 3'b0;
        reg3 <= 3'b0;
    end else begin
        if (up_down) begin
            obf_reg1 <= reg2;
            reg2 <= reg3;
            reg3 <= reg3 + 1;
        end else begin
            obf_reg1 <= reg2;
            reg2 <= reg3;
            reg3 <= reg3 - 1;
        end
    end
end

assign out = obf_reg1;

endmodule
